"""
Detects blue corner markers on the board.
Used to estimate board boundaries and tilt angles.
"""

import cv2
import numpy as np


class MarkerDetector:
    def __init__(self):
        # Blue marker HSV range (measured: H=111-116, S=255, V=71-165)
        self.lower_blue = np.array([100, 150, 50])
        self.upper_blue = np.array([130, 255, 255])

        # Expected 4 corners in order: TL, TR, BR, BL
        self.corners = None

    def detect(self, image):
        """
        Detect blue corner markers in the image.

        Returns:
            list of 4 (x, y) tuples in order [TL, TR, BR, BL],
            or None if not all 4 found.
        """
        hsv = cv2.cvtColor(image, cv2.COLOR_BGR2HSV)
        mask = cv2.inRange(hsv, self.lower_blue, self.upper_blue)

        kernel = np.ones((3, 3), np.uint8)
        mask = cv2.morphologyEx(mask, cv2.MORPH_OPEN, kernel)
        mask = cv2.morphologyEx(mask, cv2.MORPH_CLOSE, kernel)

        contours, _ = cv2.findContours(
            mask, cv2.RETR_EXTERNAL, cv2.CHAIN_APPROX_SIMPLE
        )

        # Filter by area — markers should be a certain size
        candidates = []
        for c in contours:
            area = cv2.contourArea(c)
            if 30 < area < 3000:
                M = cv2.moments(c)
                if M['m00'] > 0:
                    cx = int(M['m10'] / M['m00'])
                    cy = int(M['m01'] / M['m00'])
                    candidates.append((cx, cy))

        if len(candidates) < 4:
            return self.corners  # Return last known if not enough found

        # Sort into TL, TR, BR, BL order
        # First sort by y to get top 2 and bottom 2
        candidates.sort(key=lambda p: p[1])
        top_two = sorted(candidates[:2], key=lambda p: p[0])
        bottom_two = sorted(candidates[2:4], key=lambda p: p[0])

        self.corners = [
            top_two[0],      # Top-left
            top_two[1],      # Top-right
            bottom_two[1],   # Bottom-right
            bottom_two[0],   # Bottom-left
        ]

        return self.corners

    def estimate_tilt(self, corners):
        """
        Estimate board tilt angles from corner positions.
        Simple geometric approach using corner positions.

        Returns:
            (alpha, beta) tilt angles in degrees,
            or (0, 0) if corners not available.
        """
        if corners is None:
            return (0.0, 0.0)

        tl, tr, br, bl = corners

        # Alpha (pitch) — difference in y between left and right sides
        left_y = (tl[1] + bl[1]) / 2
        right_y = (tr[1] + br[1]) / 2
        alpha = (right_y - left_y) / 10.0  # Scale factor, tune later

        # Beta (roll) — difference in y between top and bottom
        top_y = (tl[1] + tr[1]) / 2
        bottom_y = (bl[1] + br[1]) / 2
        board_height = bottom_y - top_y

        top_x = (tl[0] + tr[0]) / 2
        bottom_x = (bl[0] + br[0]) / 2
        beta = (bottom_x - top_x) / 10.0  # Scale factor, tune later

        return (alpha, beta)